export const getReadlinkUrl = (driveID: string,
    params: ReadlinkParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/v1/drives/${driveID}/fs/readlink?${stringifiedParams}` : `/api/v1/drives/${driveID}/fs/readlink`
}

/**
 * @summary Read a symbolic link's target (POSIX readlink(2))
 */
export const readlink = async (driveID: string,
    params: ReadlinkParams, options?: RequestInit): Promise<readlinkResponse> => {

  const res = await fetch(getReadlinkUrl(driveID,params),
  {
    ...options,
    method: 'GET'


  }
)


  const body = [204, 205, 304].includes(res.status) ? null : await res.text();

  const data: readlinkResponse['data'] = body ? JSON.parse(body) : {}
  return { data, status: res.status, headers: res.headers } as readlinkResponse
}





