export const getUpsertUserUrl = () => {




  return `/api/v1/users`
}

/**
 * @summary Upsert a user from OIDC claims
 */
export const upsertUser = async (upsertUserBody?: UpsertUserBody, options?: RequestInit): Promise<upsertUserResponse> => {

  const res = await fetch(getUpsertUserUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(upsertUserBody)
  }
)


  const body = [204, 205, 304].includes(res.status) ? null : await res.text();

  const data: upsertUserResponse['data'] = body ? JSON.parse(body) : undefined
  return { data, status: res.status, headers: res.headers } as upsertUserResponse
}




